import React, { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/all";
gsap.registerPlugin(ScrollTrigger);

const datas = [
  {
    id: 0,
    title: "1. Business Needs Discovery",
    desc: "We start by gathering about your business goals and needs. This helps us plan the right AI agent that fits your workflow and tasks.",
  },
  {
    id: 1,
    title: "2. AI Agent Design",
    desc: "Our team designs the structure and features of the AI agent. We focus on simple, useful functions that solve real business problems.",
  },
  {
    id: 2,
    title: "3. Development and Testing",
    desc: "We build the AI agent and test it carefully. This step ensures the system works well, runs smoothly, and handles tasks correctly.",
  },
  {
    id: 3,
    title: "4. Launch and Ongoing Support",
    desc: "After testing, we launch the AI agent in your system. We also provide support to keep it running well and make updates when needed.",
  },
];

const DevelopmentProcess = () => {
  const timeLinecontainerRef = useRef(null);

  useEffect(() => {
    const boxes = gsap.utils.toArray(".time-line-box");

    boxes.forEach((box) => {
      ScrollTrigger.create({
        trigger: box,
        start: "top center",
        end: "bottom center",
        onEnter: () => box.classList.add("active"),
        onLeaveBack: () => box.classList.remove("active"),
      });
    });
  }, []);

  return (
    <section className="service-hero-wrapper gap-xl col_flex_column">
      <div className="col_flex_column gap-md">
        <span className="gradient-badge">Development Process</span>
        <h2 className="about-h3 c-text-center md-c-text-start">
          Our AI Agent Development Process
        </h2>
      </div>
      {/*  */}
      <div className="timeline-container" ref={timeLinecontainerRef}>
        <div className="timeline-stick"></div>

        {datas.map((data, index) => (
          <div
            key={data.id}
            className={`time-line-box ${
              index % 2 !== 0 ? "left-box" : "right-box"
            }`}
          >
            <div className="dot"></div>
            <div className="timeline-content item-start">
              <p className="about-p-two fw-600">{data.title}</p>
              <p className="about-p-two">{data.desc}</p>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default DevelopmentProcess;
